<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bouncing Ball Playground</title>
<style>
  :root {
    --bg: #0d1117;
    --panel: #161b22;
    --accent: #58a6ff;
    --text: #c9d1d9;
    --border: #30363d;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    height: 100%;
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  }
  body {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 20px;
    min-height: 100vh;
    padding: 24px;
  }
  h1 {
    margin: 0;
    font-size: 20px;
    font-weight: 600;
    letter-spacing: 0.3px;
    color: #f0f6fc;
  }
  .hint { margin: -12px 0 0; font-size: 13px; color: #8b949e; }
  #sim {
    width: 480px;
    height: 480px;
    max-width: 90vw;
    background: radial-gradient(circle at 50% 30%, #1c2430, #0d1117 70%);
    border: 1px solid var(--border);
    border-radius: 10px;
    box-shadow: 0 8px 30px rgba(0,0,0,0.5);
    cursor: crosshair;
    touch-action: none;
  }
  .controls {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid var(--border);
    padding: 10px 20px;
    font-size: 14px;
    font-weight: 500;
    border-radius: 8px;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s, transform 0.05s;
  }
  button:hover { background: #21262d; border-color: var(--accent); }
  button:active { transform: translateY(1px); }
  #play { min-width: 96px; }
</style>
</head>
<body>
  <h1>Bouncing Ball Playground</h1>
  <p class="hint">Click the canvas to drop a ball</p>
  <canvas id="sim" width="480" height="480"></canvas>
  <div class="controls">
    <button id="drop">Drop</button>
    <button id="play">Pause</button>
    <button id="clear">Clear</button>
  </div>

<script>
(function () {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  const GRAVITY = 0.35;      // downward acceleration per step
  const RESTITUTION = 0.8;   // energy retained on bounce
  const DEFAULT_R = 14;

  const COLORS = ['#58a6ff', '#f778ba', '#3fb950', '#f0883e', '#a371f7', '#e3b341', '#39c5cf'];

  let balls = [];
  let running = true;
  let colorIndex = 0;

  function randVel() { return (Math.random() * 2 - 1) * 4; }

  function addBall(x, y, vx = 0, vy = 0, r = DEFAULT_R) {
    r = Math.max(2, r);
    // keep spawn position inside the canvas
    x = Math.min(W - r, Math.max(r, x));
    y = Math.min(H - r, Math.max(r, y));
    const ball = { x, y, vx, vy, r, color: COLORS[colorIndex % COLORS.length] };
    colorIndex++;
    balls.push(ball);
    return ball;
  }

  function clear() {
    balls = [];
    draw();
  }

  function integrate(b, dt) {
    // gravity accelerates downward
    b.vy += GRAVITY * dt;
    b.x += b.vx * dt;
    b.y += b.vy * dt;

    // left / right walls
    if (b.x - b.r < 0) {
      b.x = b.r;
      b.vx = -b.vx * RESTITUTION;
    } else if (b.x + b.r > W) {
      b.x = W - b.r;
      b.vx = -b.vx * RESTITUTION;
    }

    // top / floor
    if (b.y - b.r < 0) {
      b.y = b.r;
      b.vy = -b.vy * RESTITUTION;
    } else if (b.y + b.r > H) {
      b.y = H - b.r;
      b.vy = -b.vy * RESTITUTION;
    }
  }

  function step(dt = 1) {
    for (const b of balls) integrate(b, dt);
    draw();
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);
    for (const b of balls) {
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      const grad = ctx.createRadialGradient(
        b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.1,
        b.x, b.y, b.r
      );
      grad.addColorStop(0, '#ffffff');
      grad.addColorStop(0.25, b.color);
      grad.addColorStop(1, b.color);
      ctx.fillStyle = grad;
      ctx.fill();
    }
  }

  function loop() {
    if (running) step(1);
    requestAnimationFrame(loop);
  }

  // --- Controls ---
  document.getElementById('drop').addEventListener('click', () => {
    addBall(W * (0.25 + Math.random() * 0.5), DEFAULT_R + 4, randVel(), 0);
  });

  const playBtn = document.getElementById('play');
  playBtn.addEventListener('click', () => {
    running = !running;
    playBtn.textContent = running ? 'Pause' : 'Play';
  });

  document.getElementById('clear').addEventListener('click', clear);

  canvas.addEventListener('pointerdown', (e) => {
    const rect = canvas.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (W / rect.width);
    const y = (e.clientY - rect.top) * (H / rect.height);
    addBall(x, y, randVel(), randVel());
  });

  // --- Programmatic API ---
  window.sim = {
    w: W,
    h: H,
    balls() {
      return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
    },
    addBall,
    clear,
    step,
  };

  draw();
  loop();
})();
</script>
</body>
</html>
